mapper.select:
select count(1)
from sys_invest_order
where user_id = #{userId}
  and product_id = #{productId}
  and status in ('0', '1')

select order_no as orderNo, contract_no as contractNo, create_time as createTime
from sys_invest_order
where user_id = #{userId}
  and client_req_no = #{clientReqNo}
limit 1
